  1	{
  2	  "title": "RubyLLM Models Schema",
  3	  "description": "Schema for validating the structure of models.json",
  4	  "type": "array",
  5	  "items": {
  6	    "type": "object",
  7	    "required": ["id", "name", "provider", "context_window", "max_output_tokens"],
  8	    "properties": {
  9	      "id": {
 10	        "type": "string",
 11	        "description": "Unique identifier for the model"
 12	      },
 13	      "name": {
 14	        "type": "string",
 15	        "description": "Display name of the model"
 16	      },
 17	      "provider": {
 18	        "type": "string",
 19	        "description": "Provider of the model (e.g., openai, anthropic, mistral)"
 20	      },
 21	      "family": {
 22	        "type": ["string", "null"],
 23	        "description": "Model family (e.g., gpt-4, claude-3)"
 24	      },
 25	      "created_at": {
 26	        "type": ["null", {"type": "string", "format": "date-time"}],
 27	        "description": "Creation date of the model"
 28	      },
 29	      "context_window": {
 30	        "type": ["null", {"type": "integer", "minimum": 0}],
 31	        "description": "Maximum context window size"
 32	      },
 33	      "max_output_tokens": {
 34	        "type": ["null", {"type": "integer", "minimum": 0}],
 35	        "description": "Maximum output tokens"
 36	      },
 37	      "knowledge_cutoff": {
 38	        "type": ["null", {"type": "string", "format": "date"}],
 39	        "description": "Knowledge cutoff date"
 40	      },
 41	      "modalities": {
 42	        "type": "object",
 43	        "required": ["input", "output"],
 44	        "properties": {
 45	          "input": {
 46	            "type": "array",
 47	            "items": {
 48	              "type": "string",
 49	              "enum": ["text", "image", "audio", "pdf", "video", "file"]
 50	            },
 51	            "uniqueItems": true,
 52	            "description": "Supported input modalities"
 53	          },
 54	          "output": {
 55	            "type": "array",
 56	            "items": {
 57	              "type": "string",
 58	              "enum": ["text", "image", "audio", "video", "embeddings", "moderation"]
 59	            },
 60	            "uniqueItems": true,
 61	            "description": "Supported output modalities"
 62	          }
 63	        }
 64	      },
 65	      "capabilities": {
 66	        "type": "array",
 67	        "items": {
 68	          "type": "string",
 69	          "enum": [
 70	            "streaming", "function_calling", "structured_output", "predicted_outputs",
 71	            "distillation", "fine_tuning", "batch", "realtime", "image_generation",
 72	            "speech_generation", "transcription", "translation", "citations", "reasoning",
 73	            "caching", "moderation", "json_mode", "vision"
 74	          ]
 75	        },
 76	        "uniqueItems": true,
 77	        "description": "Model capabilities"
 78	      },
 79	      "pricing": {
 80	        "type": "object",
 81	        "properties": {
 82	          "text_tokens": {
 83	            "type": "object",
 84	            "required": ["standard"],
 85	            "properties": {
 86	              "standard": {
 87	                "type": "object",
 88	                "properties": {
 89	                  "input_per_million": {"type": "number", "minimum": 0},
 90	                  "cache_read_input_per_million": {"type": "number", "minimum": 0},
 91	                  "cache_write_input_per_million": {"type": "number", "minimum": 0},
 92	                  "cached_input_per_million": {"type": "number", "minimum": 0},
 93	                  "cache_creation_input_per_million": {"type": "number", "minimum": 0},
 94	                  "output_per_million": {"type": "number", "minimum": 0},
 95	                  "reasoning_output_per_million": {"type": "number", "minimum": 0}
 96	                }
 97	              },
 98	              "batch": {
 99	                "type": "object",
100	                "properties": {
101	                  "input_per_million": {"type": "number", "minimum": 0},
102	                  "output_per_million": {"type": "number", "minimum": 0}
103	                }
104	              }
105	            }
106	          },
107	          "images": {
108	            "type": "object",
109	            "properties": {
110	              "standard": {
111	                "type": "object",
112	                "properties": {
113	                  "input": {"type": "number", "minimum": 0},
114	                  "output": {"type": "number", "minimum": 0}
115	                }
116	              },
117	              "batch": {
118	                "type": "object",
119	                "properties": {
120	                  "input": {"type": "number", "minimum": 0},
121	                  "output": {"type": "number", "minimum": 0}
122	                }
123	              }
124	            }
125	          },
126	          "audio_tokens": {
127	            "type": "object",
128	            "properties": {
129	              "standard": {
130	                "type": "object",
131	                "properties": {
132	                  "input_per_million": {"type": "number", "minimum": 0},
133	                  "output_per_million": {"type": "number", "minimum": 0}
134	                }
135	              },
136	              "batch": {
137	                "type": "object",
138	                "properties": {
139	                  "input_per_million": {"type": "number", "minimum": 0},
140	                  "output_per_million": {"type": "number", "minimum": 0}
141	                }
142	              }
143	            }
144	          },
145	          "embeddings": {
146	            "type": "object",
147	            "properties": {
148	              "standard": {
149	                "type": "object",
150	                "properties": {
151	                  "input_per_million": {"type": "number", "minimum": 0}
152	                }
153	              },
154	              "batch": {
155	                "type": "object",
156	                "properties": {
157	                  "input_per_million": {"type": "number", "minimum": 0}
158	                }
159	              }
160	            }
161	          }
162	        },
163	        "description": "Pricing information for the model"
164	      },
165	      "metadata": {
166	        "type": "object",
167	        "description": "Additional metadata about the model"
168	      }
169	    }
170	  }
171	}
